const HEAP_START: usize = 0x88000000;
const HEAP_SIZE: usize = 32 * 1024 * 1024; // 32MB，足够ext4使用
const HEAP_END: usize = HEAP_START + HEAP_SIZE;

#[global_allocator]
static ALLOCATOR: LockedHeap = LockedHeap::empty();

pub fn init_heap() {
    unsafe {
        log!("Heap OK range: {:#x} ~ {:#x}", HEAP_START, HEAP_END);

        ALLOCATOR.lock().init(HEAP_START as _, HEAP_SIZE);
        log!("Heap OK range: {:#x} ~ {:#x}", HEAP_START, HEAP_END);
    }
}

pub fn list_dir<B: BlockDevice>(
    dev: &mut Jbd2Dev<B>,
    fs: &mut Ext4FileSystem,
    path: &str,
    // ) -> Result<Vec<(String, u32, u8)>, Ext4Error> {
) -> Result<(), Ext4Error> {
    // 1. 打开目录，create=false 只读打开
    let mut dir_file = rsext4::open(dev, fs, path, false)?;

    // 校验打开的是目录
    if !dir_file.inode.is_dir() {
        return Err(Ext4Error::not_dir());
    }

    // 2. 文件偏移重置到文件开头
    rsext4::lseek(&mut dir_file, 0)?;

    // 3. 读取整个目录的全部二进制数据
    let dir_size = dir_file.inode.size() as usize;
    let raw_dir_data = rsext4::read_at(dev, fs, &mut dir_file, dir_size)?;

    // 4. 迭代解析目录项
    let mut iter = DirEntryIterator::new(&raw_dir_data);

    while let Some((entry_res, _)) = iter.next() {
        let entry = entry_res;
        let name = entry.name_str().unwrap();

        // 跳过 . 和 .. 两个特殊目录
        if name == "." || name == ".." {
            continue;
        }

        log!("{}", name);
    }

    Ok(())
}

pub struct UserStackBuilder<'a, 'b> {
    uptc: &'a mut PageTable64Cursor<'b, Sv39MetaData<VirtAddr>, Rv64PTE, MyPagingHandler>,
    pub sp: usize,
}

impl<'a, 'b> UserStackBuilder<'a, 'b> {
    pub fn new(
        uptc: &'a mut PageTable64Cursor<'b, Sv39MetaData<VirtAddr>, Rv64PTE, MyPagingHandler>,
        stack_top: usize,
    ) -> Self {
        Self {
            uptc,
            sp: stack_top,
        }
    }

    pub fn push_bytes(&mut self, data: &[u8]) -> usize {
        self.sp -= data.len();
        unsafe {
            core::ptr::copy_nonoverlapping(data.as_ptr(), self.sp() as *mut u8, data.len());
        }
        self.sp
    }

    pub fn push_cstr(&mut self, s: &str) -> usize {
        let mut buf = Vec::new();
        buf.extend_from_slice(s.as_bytes());
        buf.push(0);
        self.push_bytes(&buf)
    }

    pub fn push_usize(&mut self, value: usize) {
        self.sp -= core::mem::size_of::<usize>();
        unsafe {
            *(self.sp() as *mut usize) = value;
        }
    }

    pub fn align16(&mut self) {
        self.sp &= !15;
    }

    pub fn sp(&self) -> usize {
        self.uptc.query(self.sp.into()).unwrap().0.as_usize()
    }
}

