use crate::{current_process, kernel_core, log, trace, AddressSpace};

pub struct MyPagingHandler {
    free_area: [Vec<usize>; 18],
    pub free: usize,
}

// static mut PTC: Option<PageTable64Cursor<Sv39MetaData<VirtAddr>, Rv64PTE, MyPagingHandler>> = None;
static mut CHILD_PT: *mut PageTable64<Sv39MetaData<VirtAddr>, Rv64PTE, MyPagingHandler> =
    core::ptr::null_mut();

fn copy_frame(level: usize, idx: usize, va: VirtAddr, pte: &Rv64PTE) {
    unsafe {
        if pte.flags().contains(MappingFlags::USER) {
            let ptc = CHILD_PT.as_mut().unwrap();
            let src = pte.paddr().as_usize();
            let dst = kernel_core().pager.as_mut().unwrap().alloc(0).unwrap();
            ptr::copy(src as *const u8, dst as _, PAGE_SIZE_4K);

            let r = ptc
                .cursor()
                .map(va, dst.into(), PageSize::Size4K, pte.flags());
            if r.is_err() {
                ptc.walk(usize::MAX, Some(&print_pte_info), None);
                log!("{:X} {:?}", va, r);
            }
            r.unwrap();
        }
    }
}

/// 页表遍历打印回调，打印每一条PTE完整信息
pub fn print_pte_info(level: usize, idx: usize, va: VirtAddr, pte: &Rv64PTE) {
    trace!(
        "[PT Walk] Lv={level} | idx={idx:02} | VA={va:#x} | PTE={:?}",
        pte
    );
}

impl MyPagingHandler {
    pub fn deep_clone(
        pt: &mut AddressSpace,
    ) -> PageTable64<Sv39MetaData<VirtAddr>, Rv64PTE, MyPagingHandler> {
        let mut child_pt = PageTable64::try_new().unwrap();
        unsafe { CHILD_PT = &mut child_pt as _ };
        pt.pt.walk(usize::MAX, Some(&copy_frame), None);
        child_pt
    }

    pub fn new(mut addr: usize, mut size: usize) -> Self {
        assert!(addr & 0xfff == 0);
        assert!(size & 0xfff == 0);

        let mut pager = Self {
            free_area: [const { Vec::new() }; 18],
            free: size,
        };

        while size > 0 {
            // 找到一个合适的 order
            let mut order = 17;
            let mut page_size = 4096 << 17;
            while order > 0 {
                if (addr & (page_size - 1)) == 0 && (size >= page_size) {
                    break;
                }

                order -= 1;
                page_size >>= 1;
            }
            pager.free_area[order].push(addr);
            addr += page_size;
            size -= page_size;
        }

        pager
    }

    pub fn alloc(&mut self, order: usize) -> Option<usize> {
        // log!("alloc {:X}", self.free);

        // 找到最小可用 order
        let mut found = order;
        while self.free_area[found].is_empty() {
            found += 1;
            if found == self.free_area.len() {
                log!("free={:?}", self.free);
                log!("num of processes={}", kernel_core().processes.len());
                panic!("没空间了");
                return None;
            }
        }

        // 从当前 order 取出区域
        let res = self.free_area[found].pop().unwrap();
        let len = 1 << (order + 12);
        let buf = unsafe { from_raw_parts_mut(res as *mut u8, len) };
        buf.fill(0);

        // 把拆出来的其它塞回去
        for o in order..found {
            self.free_area[o].push(res + (4096 << o));
        }

        self.free -= 1 << (order + 12);
        Some(res)
    }

    pub fn free(&mut self, mut addr: usize, mut order: usize) {
        // log!("dealloc {:X}", self.free);
        assert!(addr & 0xfff == 0);

        loop {
            let size = order << 12;
            let buddy = addr ^ size;

            let Some(pos) = self.free_area[order].iter().position(|a| *a == buddy) else {
                // buddy 非空闲
                self.free_area[order].push(addr);
                break;
            };

            self.free_area[order].swap_remove(pos);

            addr = addr.min(buddy);
            // todo: 理论上 order 会有溢出风险
            order += 1;
        }

        self.free += 1 << (order + 12);
    }
}

impl PagingHandler for MyPagingHandler {
    fn alloc_frames(num: usize, align: usize) -> Option<PhysAddr> {
        let align = align as u64;
        let order = num.next_power_of_two().trailing_zeros();
        assert!(align == 4096);
        let addr = kernel_core()
            .pager
            .as_mut()
            .unwrap()
            .alloc(order as _)
            .unwrap();

        Some(addr.into())
    }

    fn dealloc_frames(paddr: PhysAddr, num: usize) {
        let order = num.next_power_of_two().trailing_zeros();
        kernel_core()
            .pager
            .as_mut()
            .unwrap()
            .free(paddr.as_usize(), order as _);
    }

    fn phys_to_virt(paddr: PhysAddr) -> VirtAddr {
        VirtAddr::from(paddr.as_usize())
    }
}

unsafe impl Hal for MyPagingHandler {
    fn dma_alloc(
        pages: usize,
        direction: virtio_drivers::BufferDirection,
    ) -> (virtio_drivers::PhysAddr, core::ptr::NonNull<u8>) {
        let page_size = 4096;
        let align = page_size;
        // 复用 MyPagingHandler 的物理帧分配接口
        let paddr =
            MyPagingHandler::alloc_frames(pages, align).expect("DMA alloc physical frames failed");
        log!("alloc DMA: paddr={:#x}, pages={}", paddr.as_usize(), pages);
        // 调用统一转换函数拿到虚拟地址
        let vaddr = MyPagingHandler::phys_to_virt(paddr);
        let vptr = NonNull::new(vaddr.as_usize() as *mut u8).unwrap();
        (paddr.as_usize() as _, vptr)
    }

    unsafe fn dma_dealloc(
        paddr: virtio_drivers::PhysAddr,
        vaddr: core::ptr::NonNull<u8>,
        pages: usize,
    ) -> i32 {
        MyPagingHandler::dealloc_frames(PhysAddr::from(paddr as usize), pages);
        log!("dealloc DMA: paddr={:#x}, pages={}", paddr, pages);
        0
    }

    unsafe fn mmio_phys_to_virt(
        paddr: virtio_drivers::PhysAddr,
        size: usize,
    ) -> core::ptr::NonNull<u8> {
        let vaddr = MyPagingHandler::phys_to_virt(PhysAddr::from(paddr as usize));
        NonNull::new(vaddr.as_usize() as *mut u8).unwrap()
    }

    unsafe fn share(
        buffer: core::ptr::NonNull<[u8]>,
        direction: virtio_drivers::BufferDirection,
    ) -> virtio_drivers::PhysAddr {
        let vaddr_usize = buffer.as_ref().as_ptr() as usize;
        let va = VirtAddr::from(vaddr_usize);
        if kernel_core().processes.is_empty() {
            va.as_usize() as _
        } else {
            // log!("try share {:X} pid={}", vaddr_usize, current_process().pt);
            kernel_core().pts[current_process().pt]
                .pt
                .query(va)
                .unwrap()
                .0
                .as_usize() as _
        }
    }

    unsafe fn unshare(
        paddr: virtio_drivers::PhysAddr,
        buffer: core::ptr::NonNull<[u8]>,
        direction: virtio_drivers::BufferDirection,
    ) {
    }
}

