];

pub struct VirtIoDisk;

static mut BLK_DEVICE: Option<VirtIOBlk<MyPagingHandler, MmioTransport>> = None;

impl BlockDevice for VirtIoDisk {
    /// 读取连续N个4K块到buffer
    fn read(&mut self, buf: &mut [u8], block_id: AbsoluteBN, count: u32) -> Ext4Result<()> {
        let block_bytes = BLOCK_SIZE as u64;
        let sector_bytes = SECTOR_SIZE as u64;
        // 一个4K块 = 8个512B扇区
        let sectors_per_block = block_bytes / sector_bytes;

        // 校验缓冲区长度是否匹配
        let total_req_bytes = block_bytes * count as u64;
        if buf.len() < total_req_bytes as usize {
            todo!()
        }

        let mut buf_offset = 0;
        // 遍历每个需要读取的块
        for block_idx in 0..count {
            // 当前块的起始全局块号
            let current_block = block_id.raw() + block_idx as u64;
            // 换算成磁盘起始扇区号
            let start_sector = current_block * sectors_per_block;

            // 读取当前块的全部8个扇区
            for sector_off in 0..sectors_per_block {
                let sector_num = start_sector + sector_off;
                let mut sector_buf = [0u8; SECTOR_SIZE];
                // 调用你已实现的virtio读取函数
                read_sector(sector_num, &mut sector_buf).map_err(|_| Ext4Error::io())?;
                // 扇区数据拷贝到目标buffer
                buf[buf_offset..buf_offset + SECTOR_SIZE].copy_from_slice(&sector_buf);
                buf_offset += SECTOR_SIZE;
            }
        }
        Ok(())
    }

    // 只读设备，写入直接报错
    fn write(&mut self, buf: &[u8], block_id: AbsoluteBN, count: u32) -> Ext4Result<()> {
        let block_bytes = BLOCK_SIZE as u64;
        let sector_bytes = SECTOR_SIZE as u64;
        let sectors_per_block = block_bytes / sector_bytes;

        // 校验输入缓冲区长度合法
        let total_req_bytes = block_bytes * count as u64;
        if buf.len() < total_req_bytes as usize {
            return Err(Ext4Error::invalid_input());
        }

        let mut buf_offset = 0;
        // 遍历每一个待写入的4K块
        for block_idx in 0..count {
            let current_block = block_id.raw() + block_idx as u64;
            let start_sector = current_block * sectors_per_block;

            // 遍历块内所有512字节扇区
            for sector_off in 0..sectors_per_block {
                let sector_num = start_sector + sector_off;
                // 截取当前扇区数据
                let sector_data = &buf[buf_offset..buf_offset + SECTOR_SIZE];
                let mut sector_buf = [0u8; SECTOR_SIZE];
                sector_buf.copy_from_slice(sector_data);

                // 调用virtio底层写扇区
                write_sector(sector_num, &sector_buf).map_err(|_| Ext4Error::io())?;

                buf_offset += SECTOR_SIZE;
            }
        }

        Ok(())
    }

    // 返回文件系统块大小（固定4096）
    fn block_size(&self) -> u32 {
        BLOCK_SIZE as _
    }

    // 可选：返回磁盘总块数，不实现返回0即可
    fn total_blocks(&self) -> u64 {
        // 你的img总容量 / 4096
        0
    }

    /// 设备打开钩子，只读无操作
    fn open(&mut self) -> Result<(), Ext4Error> {
        Ok(())
    }

    /// 设备关闭钩子，无操作
    fn close(&mut self) -> Result<(), Ext4Error> {
        Ok(())
    }

    /// 无RTC时钟，返回固定时间戳
    fn current_time(&self) -> Result<Ext4Timestamp, Ext4Error> {
        // 固定时间：2025-01-01，秒数
        Ok(Ext4Timestamp::new(1735689600, 0))
    }
}

fn read_sector(block_idx: u64, buf: &mut [u8; 512]) -> Result<(), virtio_drivers::Error> {
    unsafe {
        BLK_DEVICE
            .as_mut()
            .unwrap()
            .read_blocks(block_idx as _, buf)
    }
}

fn write_sector(block_idx: u64, buf: &[u8; 512]) -> Result<(), virtio_drivers::Error> {
    unsafe {
        BLK_DEVICE
            .as_mut()
            .unwrap()
            .write_blocks(block_idx as _, buf)
    }
}

/// 扫描所有 MMIO 设备，初始化 virtio-blk
pub fn init_virtio_blk() {
    for &mmio_base in &MMIO_BASES {
        let header_ptr = NonNull::new(mmio_base as *mut VirtIOHeader);
        let Some(header) = header_ptr else {
            continue;
        };
        // 构造 MMIO 传输层，MMIO 区域固定 4KB
        let transport = match unsafe { MmioTransport::new(header, 4096) } {
            Ok(t) => t,
            Err(_) => continue,
        };
        // 判断设备类型是否为块设备
        if transport.device_type() != DeviceType::Block {
            continue;
        }
        // 初始化 virtio-blk 驱动
        let blk = VirtIOBlk::<MyPagingHandler, _>::new(transport).unwrap();
        unsafe {
            BLK_DEVICE = Some(blk);
        }

        log!("Success init virtio-blk at MMIO {:#x}", mmio_base);

        let mut dev = Jbd2Dev::initial_jbd2dev(0, VirtIoDisk, /*use_journal=*/ false);

        let mut fs = rsext4::mount(&mut dev).unwrap();

        kernel_core().dev = Some(dev);
        kernel_core().fs = Some(fs);

        // list_dir(&mut dev, &mut fs, "/").unwrap();
        return;
    }
    log!("No virtio-blk MMIO device found!");
}

use core::ptr;

pub struct BufWriter {
    ptr: *mut u8,
    pos: usize,
}

impl BufWriter {
    pub unsafe fn new(addr: usize) -> Self {
        Self {
            ptr: addr as *mut u8,
            pos: 0,
        }
    }

    pub fn put_64(&mut self, v: u64) {
        unsafe {
            ptr::copy_nonoverlapping(v.to_le_bytes().as_ptr(), self.ptr.add(self.pos), 8);
        }
        self.pos += 8;
    }

    pub fn put_32(&mut self, v: u32) {
        unsafe {
            ptr::copy_nonoverlapping(v.to_le_bytes().as_ptr(), self.ptr.add(self.pos), 4);
        }
        self.pos += 4;
    }

    pub fn put_16(&mut self, v: u16) {
        unsafe {
            ptr::copy_nonoverlapping(v.to_le_bytes().as_ptr(), self.ptr.add(self.pos), 2);
        }
        self.pos += 2;
    }

    pub fn put(&mut self, v: u8) {
        unsafe {
            *self.ptr.add(self.pos) = v;
        }
        self.pos += 1;
    }

    pub fn put_all(&mut self, data: &[u8]) {
        unsafe {
            ptr::copy_nonoverlapping(data.as_ptr(), self.ptr.add(self.pos), data.len());
        }
        self.pos += data.len();
    }

    pub fn pos(&self) -> usize {
        self.pos
    }
}

