/// RISC-V SBI（Supervisor Binary Interface）调用
/// SBI Extension ID for Console (Legacy): 0x01
/// SBI Function ID for sbi_console_putchar: 0x00
#[inline(always)]
fn sbi_putchar(c: u8) {
    const SBI_EXT_CONSOLE_LEGACY: usize = 0x01;
    const SBI_FID_PUTCHAR: usize = 0x00;

    sbi_call(SBI_EXT_CONSOLE_LEGACY, SBI_FID_PUTCHAR, c as usize, 0);
}

#[inline(always)]
fn sbi_getchar() -> u8 {
    let uart = 0x1000_0000 as *mut u8;

    loop {
        let lsr = unsafe { uart.add(5).read_volatile() };

        if lsr & 1 != 0 {
            let ch = unsafe { uart.read_volatile() };
            return ch;
        }
    }
}

