#[derive(Debug, Clone)]
pub enum TrapKind {
    UserEcall { num: usize, args: [usize; 6] },
    Breakpoint,
    InstructionPageFault { va: usize },
    LoadPageFault { va: usize },
    StorePageFault { va: usize },
    IllegalInstruction,
    Unknown { scause: usize, stval: usize },
}

impl TrapFrame {
    pub fn trap_kind(&self) -> TrapKind {
        match self.scause {
            8 => {
                let num = self.a7;
                let args = [self.a0, self.a1, self.a2, self.a3, self.a4, self.a5];
                TrapKind::UserEcall { num, args }
            }
            3 => TrapKind::Breakpoint,
            12 => TrapKind::InstructionPageFault { va: self.stval },
            13 => TrapKind::LoadPageFault { va: self.stval },
            15 => TrapKind::StorePageFault { va: self.stval },
            2 => TrapKind::IllegalInstruction,
            sc => TrapKind::Unknown {
                scause: sc,
                stval: self.stval,
            },
        }
    }
    pub fn skip_ecall(&mut self) {
        self.sepc += 4;
    }
    pub fn set_ret(&mut self, val: usize) {
        self.a0 = val;
    }
}

