fn unmap_pages(
    pt: &mut PageTable64Cursor<Sv39MetaData<VirtAddr>, Rv64PTE, MyPagingHandler>,
    mut range: Range<usize>,
) {
    range.start = range.start & !0xfff;
    let page_count = (((range.end + PAGE_SIZE_4K - 1) & !0xfff) - range.start) >> 12;

    trace!("{:X} unmap_pages {:X} ~ {:X}", pt.root_paddr(), range.start, range.end);

    for i in 0..page_count {
        let va_base = memory_addr::VirtAddr::from_usize(range.start + i * PAGE_SIZE_4K);

        if let Ok((pa, _, _)) = pt.query(va_base)
        {
            kernel_core().pager.as_mut().unwrap().free(pa.as_usize(), 0);

            let r = pt.unmap(va_base);
            // r.unwrap();
        }
    }

    // 刷新地址转换缓存
    unsafe {
        asm!("sfence.vma zero, zero");
    }
}

fn read_cstr(mut filename_ptr: *const u8) -> String {
    let mut filename = String::new();
    unsafe {
        while filename_ptr.read() != 0 {
            filename.push(filename_ptr.read() as char);
            filename_ptr = filename_ptr.byte_add(1);
        }
    }
    filename
}

fn read_argv(argv_va: usize) -> Vec<String> {
    let mut result = Vec::new();

    let mut ptr = argv_va as *const usize;

    loop {
        let str_ptr = unsafe { *ptr };

        if str_ptr == 0 {
            break;
        }

        result.push(read_cstr(str_ptr as *const u8));

        ptr = unsafe { ptr.add(1) };
    }

    result
}

#[no_mangle]
pub extern "C" fn temporary_trap_handler(tf: &mut TrapFrame) {
    // log!("before sepc={:#x}", tf.sepc);

    // log!("user sp={:#x}", tf.x[2]);
    // log!("user ra={:#x}", tf.x[1]);

    // for i in 0..32 {
    //     log!("x{} = {:#x}", i, tf.x[i]);
    // }

    match tf.trap_kind() {
        TrapKind::UserEcall { num, args } => {
            tf.skip_ecall();
            let op = SyscallOp::from_sys(num, args);
            let ret = dispatch_syscall(tf, op);
            tf.set_ret(ret);
        }
        TrapKind::Breakpoint => {
            log!("breakpoint");
            tf.sepc += 4;
        }

        // 指令缺页
        TrapKind::InstructionPageFault { va } => {
            log!("🚨 Instruction Page Fault");
            log!("fault va = {va:#x}");
            log!("sepc    = {:#x}", tf.sepc);
            // 无实现，死循环挂起内核
            unrecoverable();
        }

        // 加载(读内存)缺页
        TrapKind::LoadPageFault { va } => {
            log!("🚨 Load Page Fault");
            log!("fault va = {va:#x}");
            log!("sepc    = {:#x}", tf.sepc);
            log!("tp      = {:#x}", tf.tp);
            unrecoverable();
        }

        // 存储(写内存)缺页
        TrapKind::StorePageFault { va } => {
            log!("🚨 Store Page Fault");
            log!("fault va = {va:#x}");
            log!("sepc    = {:#x}", tf.sepc);
            log!("sstatus    = {:#x}", tf.sstatus);
            unrecoverable();
        }

        // 非法指令
        TrapKind::IllegalInstruction => {
            log!("🚨 Illegal Instruction");
            log!("sepc = {:#x}", tf.sepc);
            unrecoverable();
        }

        // 未知陷阱，打印完整上下文并挂起
        TrapKind::Unknown { scause, stval } => {
            log!("🚨 [内核 TRAP 崩溃捕获] 🚨");
            log!("scause={:#x}", scause);
            log!("stval ={:#x}", stval);
            log!("sepc  ={:#x}", tf.sepc);
              unrecoverable();
        }
    }
}

pub fn exit_program(code: i32) -> ! {
    trace!("程序退出 退出码 {code}");
    let c = kernel_core();
    let fs = c.fs.as_mut().unwrap();
    let dev = c.dev.as_mut().unwrap();
    trace!("{:X?}", fs.sync_filesystem(dev));
    // let popped = c.processes.pop().unwrap();
    let p = current_process();
    let pid = p.pid;
    p.set_state(ProcessState::Zombie(code as _));

    // 释放资源
    for f in p.files.iter().filter(|f| f.occupied()) {
        match &kernel_core().files[f.idx] {
            FdResource::Stdin => {}
            FdResource::Stdout => {}
            FdResource::Stderr => {}
            FdResource::File(open_file) => {}
            FdResource::PipeRead(i) => {
                if let Some(pos) = c.pipes[*i].readers.iter().position(|id| *id == p.pid) {
                    c.pipes[*i].readers.swap_remove(pos);
                }
                for pid in c.pipes[*i].writers.iter() {
                    c.processes[pid - 1].set_state(ProcessState::Ready);
                }
            }
            FdResource::PipeWrite(i) => {
                if let Some(pos) = c.pipes[*i].writers.iter().position(|id| *id == p.pid) {
                    c.pipes[*i].writers.swap_remove(pos);
                }
                for pid in c.pipes[*i].readers.iter() {
                    c.processes[pid - 1].set_state(ProcessState::Ready);
                }
            }
        }
    }

    {
        let uptc = &mut c.pts[p.pt].pt.cursor();

        // 释放 mmap
        let mut mmaps = vec![];
        swap(&mut mmaps, &mut p.mmaps);
        for (addr, len) in mmaps {
            unmap_pages(uptc, addr..addr + len);
        }

        trace!("uptcr={:X}", uptc.root_paddr());

        // 回收用户栈
        // unmap_pages(uptc, USER_STACK_VA - USER_STACK_SIZE..USER_STACK_VA);

        //  回收内核栈
        // todo: 现在还用着内核栈，暂时等父类回收
        // unmap_pages(uptc, STACK_VA - STACK_SIZE..STACK_VA);
    }

    let Some(parent) = p.parent else {
        sbi_shutdown();
    };

    c.sched_in(parent, "子进程退出，调父进程");
    // c.schedule();

    unreachable!()
}

