#[unsafe(no_mangle)] // 按照你的要求，将 no_mangle 属性用 unsafe 包裹
#[unsafe(link_section = ".text.init")] // 按照你的要求，将 link_section 属性用 unsafe 包裹
pub unsafe extern "C" fn _start() -> ! {
    core::arch::naked_asm!(
        // 1. 设置栈指针 (sp) 到 RAM 的最高地址 (向下增长)
        // la sp, __stack_top (load address)
        "la sp, __stack_top",
        // 2. 清零 BSS 段 (使用 64 位指令 sd 和 8 字节递增)
        // a0 = __bss_start, t1 = __bss_end
        "la t0, __bss_start", // 修复了隐藏的 Unicode 空格
        "la t1, __bss_end",   // 修复了隐藏的 Unicode 空格
        "bge t0, t1, 2f",     // 如果 BSS 为空，跳到 2f
        "1:",                 // 循环标签 1
        "sd zero, 0(t0)",     // 64位修复：将 0 存入当前地址 (Store Doubleword, 8字节清零)
        "addi t0, t0, 8",     // 64位修复：地址递增 8 字节
        "blt t0, t1, 1b",     // 如果 a0 < a1，继续循环
        "2:",                 // 结束标签 2 (BSS 清零完成)
        // 3. 跳转到 Rust 主函数 kmain
        "call kmain",
        // 4. 理论上 kmain 是一个发散函数 (never returns)，但以防万一
        "j _start",
    )
}

