#[repr(C)]
#[derive(Default, Debug, Clone, Copy)]
pub struct Stat {
    pub st_dev: u64,
    pub st_ino: u64,
    pub st_mode: u32,
    pub st_nlink: u32,

    pub st_uid: u32,
    pub st_gid: u32,
    pub __pad0: u32,

    pub st_rdev: u64,
    pub st_size: i64,
    pub st_blksize: i64,
    pub st_blocks: i64,

    pub st_atime: i64,
    pub st_atime_nsec: i64,

    pub st_mtime: i64,
    pub st_mtime_nsec: i64,

    pub st_ctime: i64,
    pub st_ctime_nsec: i64,

    pub __unused: [i32; 2],
}
impl Stat {
    fn set_from(&mut self, file: &OpenFile) {
        let inode = &file.inode;

        self.st_dev = 0;
        self.st_ino = file.inode_num.as_u64(); // 如果你有 inode 编号的话

        // 文件类型 + 权限
        self.st_mode = inode.i_mode as u32;

        // 硬链接数
        self.st_nlink = inode.i_links_count as u32;

        // uid/gid
        self.st_uid = inode.uid();
        self.st_gid = inode.gid();

        self.__pad0 = 0;

        // 设备文件暂时不支持
        self.st_rdev = 0;

        // 文件大小
        self.st_size = inode.size() as i64;

        // ext4 block size 一般 4K
        self.st_blksize = 4096;

        // 512-byte blocks
        self.st_blocks = ((inode.size() + 511) / 512) as i64;

        // 时间
        self.st_atime = inode.i_atime as i64;
        self.st_atime_nsec = 0;

        self.st_mtime = inode.i_mtime as i64;
        self.st_mtime_nsec = 0;

        self.st_ctime = inode.i_ctime as i64;
        self.st_ctime_nsec = 0;

        self.__unused = [0; 2];
    }
}

