fn syscall_write(fd: usize, buf_ptr: usize, len: usize) -> usize {
    let data = unsafe { core::slice::from_raw_parts(buf_ptr as *const u8, len) };
    match current_process().fd(fd) {
        Some(FdResource::Stdout) | Some(FdResource::Stderr) => {
            for ele in data {
                if ENABLE_OUTPUT {
                    sbi_putchar(*ele);
                }
            }
            len
        }
        Some(FdResource::File(f)) => {
            let dev = kernel_core().dev.as_mut().unwrap();
            let fs = kernel_core().fs.as_mut().unwrap();
            let r = rsext4::write_at(dev, fs, f, data);
            match r {
                Ok(()) => len,
                Err(err) => (-(err.code.as_i32() as isize)) as _,
            }
        }
        Some(FdResource::PipeWrite(idx)) => {
            let p = &mut kernel_core().pipes[*idx];
            let rec_buf = unsafe { from_raw_parts(buf_ptr as _, len) };

            loop {
                if p.readers.len() == 0 {
                    break -1isize as _; // Broken pipe
                }
                let space = 4096 - p.buf.len();
                trace!("space={space}");
                if space == 0 {
                    // 挂起
                    current_process().set_state(ProcessState::Waiting);

                    trace!("可用读进程{:?}", p.readers);
                    let target = p.readers.last().unwrap();
                    kernel_core().sched_in(*target, "写管道挂起，调读进程");
                } else {
                    // 写入
                    let l = len.min(space);
                    for i in 0..l {
                        p.buf.push_back(rec_buf[i]);
                    }
                    break l;
                }
            }
        }
        _ => len, // 暂时忽略

                  // _ => unimplemented!(),
    }
}

fn syscall_read(fd: usize, buf_ptr: usize, len: usize) -> usize {
    match current_process().fd(fd) {
        Some(FdResource::Stdin) => {
            let dst = unsafe { from_raw_parts_mut(buf_ptr as *mut u8, len) };

            let mut i = 0;
            while i < len {
                let ch = sbi_getchar();
                if ch == b'\r' {
                    dst[i] = b'\n';
                    i += 1;
                    break;
                } else {
                    dst[i] = ch;
                    i += 1;
                }
            }
            i
        }
        Some(FdResource::File(open_file)) => {
            let dev = kernel_core().dev.as_mut().unwrap();
            let fs = kernel_core().fs.as_mut().unwrap();
            let data = rsext4::read_at(dev, fs, open_file, len).unwrap();
            let dst = unsafe { from_raw_parts_mut(buf_ptr as _, len) };
            dst[..data.len()].copy_from_slice(&data);

            data.len()
        }
        Some(FdResource::PipeRead(idx)) => {
            let p = &mut kernel_core().pipes[*idx];
            let rec_buf = unsafe { from_raw_parts_mut(buf_ptr as _, len) };

            loop {
                let len = min(len, p.buf.len());
                if len == 0 {
                    if p.writers.len() == 0 {
                        break 0;
                    }
                    // 挂起
                    current_process().set_state(ProcessState::Waiting);

                    // 唤醒
                    trace!("可用写进程{:?}", p.writers);
                    let target = p.writers.last().unwrap();
                    kernel_core().sched_in(*target, "读管道挂起，调写进程");
                } else {
                    // 读取
                    for i in 0..len {
                        rec_buf[i] = p.buf.pop_front().unwrap();
                    }
                    break len;
                }
            }
        }
        _ => len, // 暂时忽略

                  // _ => unimplemented!(),
    }
}

