        None => {}
        Some(FdResource::Stdin) => {}
        Some(FdResource::Stdout) => {}
        Some(FdResource::Stderr) => {}
        Some(FdResource::File(open_file)) => {}
        Some(FdResource::PipeRead(i)) => {
            let readers = &mut kernel_core().pipes[*i].readers;
            trace!("{:?}", readers);
            // todo: 计数
            let i = readers
                .iter()
                .position(|p| *p == current_process().pid)
                .unwrap();
            readers.remove(i);
        }
        Some(FdResource::PipeWrite(i)) => {
            let writers = &mut kernel_core().pipes[*i].writers;
            // todo: 计数
            let i = writers
                .iter()
                .position(|p| *p == current_process().pid)
                .unwrap();
            writers.remove(i);
        }
    };
    current_process().files[fd] = Fd::default();
}

