fn sbi_call(eid: usize, fid: usize, mut arg0: usize, mut arg1: usize) -> usize {
    unsafe {
        core::arch::asm!(
            "ecall",
            inout("a0") arg0,
            inout("a1") arg1,
            in("a6") fid,
            in("a7") eid,
        );
    }

    assert_eq!(arg0, 0);

    arg1
}

/// RISC-V SBI 系统关机调用
/// EID: 0x53525354 (SRST), FID: 0x00 (shutdown)
fn sbi_shutdown() -> ! {
    const SBI_EXT_SRST: usize = 0x53525354; // S R S T
    const SBI_FID_SHUTDOWN: usize = 0x00;

    sbi_call(SBI_EXT_SRST, SBI_FID_SHUTDOWN, 0, 0);

    unreachable!();
}

