fn do_iov(iov: usize, iovcnt: usize, mut f: impl FnMut(&IoVec) -> usize) -> usize {
    let iovs = unsafe { core::slice::from_raw_parts(iov as *const IoVec, iovcnt) };

    let mut total = 0;

    for v in iovs {
        let ret = f(v);

        let n = ret as isize;

        if n < 0 {
            if total > 0 {
                break;
            }

            return ret;
        }

        total += n as usize;

        // 当前 buf 没用满，直接返回。
        if (n as usize) < v.len {
            break;
        }
    }

    total
}

fn alloc_fd(from: Option<usize>) -> usize {
    let from = from.unwrap_or(0);

    let Some(idx) = current_process()
        .files
        .iter()
        .skip(from)
        .position(|f| f.idx == 0)
    else {
        log!("{:?}", current_process().files);
        panic!("打开的文件数量已达上限");
    };

    idx + from
