            _ => {
                log!("不是文件");
                panic!();
            }
        }
    }

    fn set_state(&mut self, new_state: ProcessState) {
        match self.state {
            ProcessState::Zombie(_) => {}
            _ => {
                self.state = new_state;
            }
        }
    }
}

